// count-up animation for numeric trust stats (triggers on scroll into view)
(function statCountUp(){
  const nums = document.querySelectorAll('.stat-num[data-num]');
  if(!nums.length) return;
  const reduceM = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
  if(reduceM){ nums.forEach(el=> el.textContent = el.dataset.num + (el.dataset.suf||'')); return; }
  function run(el){
    const target = +el.dataset.num, suf = el.dataset.suf || '', dur = 1300, t0 = performance.now();
    function step(now){
      const p = Math.min(1, (now - t0) / dur);
      const e = 1 - Math.pow(1 - p, 3); // easeOutCubic
      el.textContent = Math.round(target * e) + suf;
      if(p < 1) requestAnimationFrame(step); else el.textContent = target + suf;
    }
    requestAnimationFrame(step);
  }
  const io = new IntersectionObserver((entries)=>{
    entries.forEach(en=>{ if(en.isIntersecting){ run(en.target); io.unobserve(en.target); } });
  }, { threshold: 0.4 });
  nums.forEach(el=>{ el.textContent = '0' + (el.dataset.suf || ''); io.observe(el); });
})();

