const onScroll = ()=>{
  if(window.scrollY>24){ navbar.className='container-x flex items-center justify-between rounded-2xl border border-white/10 px-5 py-3 backdrop-blur-xl transition-all duration-500'; navbar.style.background='rgba(12,17,27,.85)'; navbar.style.boxShadow='0 24px 60px -28px rgba(8,12,22,.55)'; }
  else { navbar.className='container-x flex items-center justify-between rounded-2xl border border-white/[0.06] bg-white/[0.02] px-5 py-3 backdrop-blur-md transition-all duration-500'; navbar.style.background=''; navbar.style.boxShadow=''; }
};
window.addEventListener('scroll', onScroll, {passive:true}); onScroll();

// lang toggle
document.querySelectorAll('.lang-btn').forEach(b=>b.addEventListener('click',()=>{
  document.querySelectorAll('.lang-btn').forEach(x=>{x.className='lang-btn rounded-md px-2.5 py-1 text-ink/50 hover:text-ink';});
  b.className='lang-btn rounded-md px-2.5 py-1 accent-grad text-dark-text';
}));

// form
document.getElementById('protocolForm').addEventListener('submit', e=>{
  e.preventDefault();
  e.target.classList.add('hidden');
  const s=document.getElementById('formSuccess'); s.classList.remove('hidden'); s.classList.add('flex');
});

// scroll reveal
const reduce = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
if(reduce){ document.querySelectorAll('.reveal').forEach(r=>r.classList.add('in')); }
else {
  const io = new IntersectionObserver((entries)=>{ entries.forEach(en=>{ if(en.isIntersecting){ en.target.classList.add('in'); io.unobserve(en.target); } }); }, {rootMargin:'-80px'});
  document.querySelectorAll('.reveal').forEach(r=>io.observe(r));
}

// catalog pen-icon 3D tilt (cursor tracked, ±18°)
if(!reduce){
  const cg = document.getElementById('catalogGrid');
  cg.addEventListener('pointermove', e=>{
    const icon = e.target.closest('.pen-icon'); if(!icon) return;
    const t = icon.querySelector('.pen-tilt'); const r = icon.getBoundingClientRect();
    const x=(e.clientX-r.left)/r.width-0.5, y=(e.clientY-r.top)/r.height-0.5;
    t.style.transform='rotateY('+(x*36).toFixed(1)+'deg) rotateX('+(-y*36).toFixed(1)+'deg)';
  });
  cg.addEventListener('pointerout', e=>{
    const icon = e.target.closest('.pen-icon'); if(!icon || icon.contains(e.relatedTarget)) return;
    const t = icon.querySelector('.pen-tilt'); if(t) t.style.transform='';
  });
}

const HERO_PENS = [{"name": "WolverMax", "sub": "BPC-157 + TB-500", "acc": "#4fffb0", "img": "data:image/png;base64,"}, {"name": "NADMax", "sub": "NAD+", "acc": "#38bdf8", "img": "data:image/png;base64,"}, {"name": "MOTS-Max", "sub": "MOTS-C", "acc": "#00f2fe", "img": "data:image/png;base64,"}];

// ===== Hero single-pen slider (autoplay, hover-pause, 3D tilt, per-product glow) =====
(function heroSlider(){
  const root = document.getElementById('heroPen');
  if(!root || typeof HERO_PENS === 'undefined') return;
  const stage = document.getElementById('heroStage');
  const tabs  = document.getElementById('heroTabs');
  const glow  = root.querySelector('.hero-pen-glow');
  const DUR = 4200;
  const reduceM = window.matchMedia('(prefers-reduced-motion: reduce)').matches;

  stage.innerHTML = HERO_PENS.map((p,i)=>
    '<div class="hero-slide" data-i="'+i+'"><div class="hero-tilt"><img class="hero-pen-img" src="'+p.img+'" alt="PeptidePen '+p.name+'" draggable="false"/></div></div>'
  ).join('');
  tabs.innerHTML = HERO_PENS.map((p,i)=>
    '<button class="hero-tab" data-i="'+i+'" style="--acc:'+p.acc+'" type="button"><span class="ht-name">'+p.name+'</span><span class="ht-sub">'+p.sub+'</span><span class="ht-prog"></span></button>'
  ).join('');

  const slides = Array.from(stage.children);
  const tabEls = Array.from(tabs.children);
  let cur = -1, timer = null, hovering = false;
  root.style.setProperty('--dur', DUR+'ms');

  // ---- slide sound (provided audio: "Surgical Grace") ----
  const SLIDE_SOUND = "data:audio/wav;base64,";
  let isSoundEnabled = false;
  try { isSoundEnabled = localStorage.getItem('pmx-sound') === 'on'; } catch(e){}
  let isAudioUnlocked = false, hasUserInteracted = false;
  const slideAudio = new Audio(SLIDE_SOUND);
  slideAudio.preload = 'auto';
  slideAudio.volume = 0.5;
  function unlockAudio(){
    hasUserInteracted = true;
    if(isAudioUnlocked) return;
    isAudioUnlocked = true;
    // prime the element within the user gesture so later programmatic plays are allowed
    try {
      slideAudio.muted = true;
      const pr = slideAudio.play();
      if(pr && pr.then){ pr.then(()=>{ slideAudio.pause(); slideAudio.currentTime = 0; slideAudio.muted = false; }).catch(()=>{ slideAudio.muted = false; }); }
      else { slideAudio.pause(); slideAudio.currentTime = 0; slideAudio.muted = false; }
    } catch(e){ slideAudio.muted = false; }
  }
  function playSlideSound(){
    if(!isSoundEnabled || !isAudioUnlocked || document.hidden) return;
    try { slideAudio.currentTime = 0; const pr = slideAudio.play(); if(pr && pr.catch) pr.catch(()=>{}); } catch(e){}
  }

  function setActive(i){
    if(i === cur) return;
    const prevIdx = cur;
    slides.forEach((s,j)=>{
      s.classList.remove('is-exit');
      if(j === cur) s.classList.add('is-exit');
      s.classList.toggle('is-active', j === i);
    });
    tabEls.forEach((t,j)=> t.classList.toggle('is-active', j === i));
    const acc = HERO_PENS[i].acc;
    root.style.setProperty('--acc', acc);
    glow.style.background = acc;
    cur = i;
    if(prevIdx !== -1) playSlideSound();
  }
  function next(){ setActive((cur+1) % HERO_PENS.length); }
  function play(){ stop(); if(!reduceM && !hovering) timer = setInterval(next, DUR); }
  function stop(){ if(timer){ clearInterval(timer); timer = null; } }

  tabs.addEventListener('click', e=>{
    const b = e.target.closest('.hero-tab'); if(!b) return;
    setActive(+b.dataset.i); play();
  });

  // hover: pause autoplay, keep tilt; resume on leave
  root.addEventListener('pointerenter', ()=>{ hovering = true; stop(); });
  root.addEventListener('pointerleave', ()=>{
    hovering = false;
    play();
    const t = slides[cur] && slides[cur].querySelector('.hero-tilt');
    if(t) t.style.transform = '';
  });
  if(!reduceM){
    root.addEventListener('pointermove', e=>{
      const t = slides[cur] && slides[cur].querySelector('.hero-tilt'); if(!t) return;
      const r = root.getBoundingClientRect();
      const x = (e.clientX - r.left)/r.width - 0.5, y = (e.clientY - r.top)/r.height - 0.5;
      t.style.transform = 'perspective(900px) rotateY('+(x*16).toFixed(1)+'deg) rotateX('+(-y*12).toFixed(1)+'deg)';
    });
  }

  // ---- minimal sound toggle (in hero product area) ----
  const ICON_ON = '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.7" stroke-linecap="round" stroke-linejoin="round"><path d="M4 9v6h4l5 4V5L8 9H4z"/><path d="M16 9.5a3 3 0 0 1 0 5"/><path d="M18.6 7a6 6 0 0 1 0 10"/></svg>';
  const ICON_OFF = '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.7" stroke-linecap="round" stroke-linejoin="round"><path d="M4 9v6h4l5 4V5L8 9H4z"/><path d="M17 9.5l5 5M22 9.5l-5 5"/></svg>';
  const soundBtn = document.createElement('button');
  soundBtn.type = 'button';
  soundBtn.className = 'hero-sound';
  function renderSoundBtn(){
    soundBtn.classList.toggle('is-on', isSoundEnabled);
    soundBtn.setAttribute('aria-pressed', isSoundEnabled ? 'true' : 'false');
    soundBtn.setAttribute('aria-label', isSoundEnabled ? 'Вимкнути звук слайдера' : 'Увімкнути звук слайдера');
    soundBtn.innerHTML = (isSoundEnabled ? ICON_ON : ICON_OFF) + '<span>' + (isSoundEnabled ? 'Sound On' : 'Sound Off') + '</span>';
  }
  renderSoundBtn();
  soundBtn.addEventListener('click', e=>{
    e.stopPropagation();
    isSoundEnabled = !isSoundEnabled;
    try { localStorage.setItem('pmx-sound', isSoundEnabled ? 'on' : 'off'); } catch(_){}
    if(isSoundEnabled) unlockAudio();
    renderSoundBtn();
  });
  root.appendChild(soundBtn);

  // unlock audio after first user interaction with the hero product area
  ['pointerdown','click','mouseenter'].forEach(ev => root.addEventListener(ev, unlockAudio));

  setActive(0);
  play();
})();
